// MARK: - URL Validator

struct URLValidator {
    
    private static let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    private static let allowedSchemes: Set<String> = [
        "https"
    ]
    
    private static let tokenPattern = "^[a-zA-Z0-9\\-_]{16,256}$"
    
    static func isValidUniversalLink(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              allowedSchemes.contains(scheme) else {
            print("[Security] Rejected URL with invalid scheme: \(url.scheme ?? "nil")")
            return false
        }
        
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            print("[Security] Rejected URL with invalid host: \(url.host ?? "nil")")
            return false
        }
        
        // Reject URLs with user info (e.g., https://attacker@myapp.com/...)
        if url.user != nil || url.password != nil {
            print("[Security] Rejected URL containing user info component")
            return false
        }
        
        // Reject URLs with non-standard ports
        if let port = url.port, port != 443 {
            print("[Security] Rejected URL with non-standard port: \(port)")
            return false
        }
        
        return true
    }
    
    static func isValidToken(_ token: String) -> Bool {
        guard !token.isEmpty else { return false }
        
        let predicate = NSPredicate(format: "SELF MATCHES %@", tokenPattern)
        guard predicate.evaluate(with: token) else {
            print("[Security] Token failed validation pattern check")
            return false
        }
        
        // Check for path traversal or injection attempts
        let dangerousPatterns = ["..", "/", "\\", "<", ">", "'", "\"", ";", "&", "|", "%00"]
        for pattern in dangerousPatterns {
            if token.contains(pattern) {
                print("[Security] Token contains dangerous pattern: \(pattern)")
                return false
            }
        }
        
        return true
    }
    
    static func sanitize(_ input: String) -> String {
        var sanitized = input.trimmingCharacters(in: .whitespacesAndNewlines)
        let disallowedCharacters = CharacterSet.alphanumerics
            .union(CharacterSet(charactersIn: "-_"))
            .inverted
        sanitized = sanitized.components(separatedBy: disallowedCharacters).joined()
        return sanitized
    }
}

// MARK: - Deep Link Parser

struct DeepLinkParser {
    
    static func parse(url: URL) -> DeepLinkRoute {
        guard URLValidator.isValidUniversalLink(url) else {
            print("[DeepLink] URL failed security validation")
            return .unknown
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            print("[DeepLink] Failed to parse URL components")
            return .unknown
        }
        
        let path = components.path.lowercased()
        
        switch path {
        case "/reset-password":
            return parseResetPassword(from: components)
        default:
            print("[DeepLink] Unrecognized path: \(path)")
            return .unknown
        }
    }
    
    private static func parseResetPassword(from components: URLComponents) -> DeepLinkRoute {
        guard let queryItems = components.queryItems else {
            print("[DeepLink] No query parameters found for reset-password")
            return .unknown
        }
        
        guard let tokenItem = queryItems.first(where: { $0.name == "token" }),
              let rawToken = tokenItem.value else {
            print("[DeepLink] Missing token parameter")
            return .unknown
        }
        
        let sanitizedToken = URLValidator.sanitize(rawToken)
        
        guard URLValidator.isValidToken(sanitizedToken) else {
            print("[DeepLink] Invalid token format")
            return .unknown
        }
        
        // Ensure no extra unexpected parameters that could indicate tampering
        let allowedParams: Set<String> = ["token"]
        let unexpectedParams = queryItems.filter { !allowedParams.contains($0.name) }
        if !unexpectedParams.isEmpty {
            print("[Security] Warning: Unexpected query parameters detected: \(unexpectedParams.map { $0.name })")
            // We proceed but log the warning — could also reject here depending on policy
        }
        
        return .resetPassword(token: sanitizedToken)
    }
}

// MARK: - Navigation Coordinator

protocol NavigationCoordinating: AnyObject {
    func navigateToPasswordReset(with token: String)
    func navigateToHome()
    func showError(message: String)
}

class NavigationCoordinator: NavigationCoordinating {
    
    weak var window: UIWindow?
    private var navigationController: UINavigationController? {
        return window?.rootViewController as? UINavigationController
    }
    
    init(window: UIWindow?) {
        self.window = window
    }
    
    func navigateToPasswordReset(with token: String) {
        let resetVC = PasswordResetViewController(token: token)
        
        DispatchQueue.main.async { [weak self] in
            guard let navigationController = self?.navigationController else {
                // If no navigation controller, set up fresh navigation stack
                let navController = UINavigationController(rootViewController: resetVC)
                self?.window?.rootViewController = navController
                self?.window?.makeKeyAndVisible()
                return
            }
            
            // Pop to root first to ensure clean navigation state
            navigationController.popToRootViewController(animated: false)
            navigationController.pushViewController(resetVC, animated: true)
        }
    }
    
    func navigateToHome() {
        DispatchQueue.main.async { [weak self] in
            self?.navigationController?.popToRootViewController(animated: true)
        }
    }
    
    func showError(message: String) {
        DispatchQueue.main.async { [weak self] in
            let alert = UIAlertController(
                title: "Invalid Link",
                message: message,
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "OK", style: .default) { [weak self] _ in
                self?.navigateToHome()
            })
            
            let presenter = self?.navigationController?.visibleViewController ?? self?.window?.rootViewController
            presenter?.present(alert, animated: true)
        }
    }
}

// MARK: - Deep Link Handler

class DeepLinkHandler {
    
    private let coordinator: NavigationCoordinating
    private var lastHandledURL: URL?
    private var lastHandledTime: Date?
    private let minimumHandleInterval: TimeInterval = 2.0 // Prevent rapid repeated handling
    
    init(coordinator: NavigationCoordinating) {
        self.coordinator = coordinator
    }
    
    func handleUniversalLink(_ url: URL) -> Bool {
        // Rate limiting: prevent rapid repeated handling of the same URL
        if let lastURL = lastHandledURL,
           let lastTime = lastHandledTime,
           lastURL == url,
           Date().timeIntervalSince(lastTime) < minimumHandleInterval {
            print("[DeepLink] Ignoring duplicate URL within rate limit window")
            return false
        }
        
        lastHandledURL = url
        lastHandledTime = Date()
        
        let route = DeepLinkParser.parse(url: url)
        
        switch route {
        case .resetPassword(let token):
            print("[DeepLink] Navigating to password reset")
            coordinator.navigateToPasswordReset(with: token)
            return true
            
        case .unknown:
            print("[DeepLink] Unknown or invalid deep link")
            coordinator.showError(message: "This link is invalid or has expired. Please request a new password reset link.")
            return false
        }
    }
}

