        alert.addAction(UIAlertAction(title: "Cancel", style: .destructive) { [weak self] _ in
            self?.navigationController?.popToRootViewController(animated: true)
        })
        present(alert, animated: true)
    }
    
    @objc private func resetPasswordTapped() {
        guard let newPassword = newPasswordField.text,
              let confirmPassword = confirmPasswordField.text else {
            return
        }
        
        // Client-side validation
        guard !newPassword.isEmpty, !confirmPassword.isEmpty else {
            showAlert(message: "Please fill in both password fields.")
            return
        }
        
        guard newPassword == confirmPassword else {
            showAlert(message: "Passwords do not match.")
            return
        }
        
        guard isPasswordStrong(newPassword) else {
            showAlert(message: "Password must be at least 8 characters and include uppercase, lowercase, a number, and a special character.")
            return
        }
        
        setFormEnabled(false)
        activityIndicator.startAnimating()
        
        PasswordResetService.shared.resetPassword(token: token, newPassword: newPassword) { [weak self] result in
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                
                switch result {
                case .success:
                    self?.showSuccessAndNavigate()
                case .failure(let error):
                    self?.setFormEnabled(true)
                    self?.showValidationError(error)
                }
            }
        }
    }
    
    private func isPasswordStrong(_ password: String) -> Bool {
        guard password.count >= 8 else { return false }
        
        let hasUppercase = password.range(of: "[A-Z]", options: .regularExpression) != nil
        let hasLowercase = password.range(of: "[a-z]", options: .regularExpression) != nil
        let hasDigit = password.range(of: "[0-9]", options: .regularExpression) != nil
        let hasSpecial = password.range(of: "[^a-zA-Z0-9]", options: .regularExpression) != nil
        
        return hasUppercase && hasLowercase && hasDigit && hasSpecial
    }
    
