// MARK: - Password Reset Service

enum PasswordResetError: Error {
    case tokenExpired
    case tokenInvalid
    case networkError
    case serverError
    case weakPassword
}

class PasswordResetService {
    
    static let shared = PasswordResetService()
    
    private let baseURL = "https://api.myapp.com"
    private let session: URLSession
    
    private init() {
        let configuration = URLSessionConfiguration.ephemeral
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        configuration.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        // Disable caching for sensitive operations
        configuration.urlCache = nil
        configuration.requestCachePolicy = .reloadIgnoringLocalAndRemoteCacheData
        
        self.session = URLSession(configuration: configuration)
    }
    
    func validateToken(_ token: String, completion: @escaping (Result<Void, PasswordResetError>) -> Void) {
        guard let url = URL(string: "\(baseURL)/api/v1/password-reset/validate") else {
            completion(.failure(.serverError))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.timeoutInterval = 15
        
        let body: [String: String] = ["token": token]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        } catch {
            completion(.failure(.serverError))
            return
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if error != nil {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.serverError))
                return
            }
            
            switch httpResponse.statusCode {
            case 200:
                completion(.success(()))
            case 401, 403:
                completion(.failure(.tokenInvalid))
            case 410:
                completion(.failure(.tokenExpired))
            default:
                completion(.failure(.serverError))
            }
        }
        task.resume()
    }
    
    func resetPassword(token: String, newPassword: String, completion: @escaping (Result<Void, PasswordResetError>) -> Void) {
        guard let url = URL(string: "\(baseURL)/api/v1/password-reset/confirm") else {
            completion(.failure(.serverError))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.timeoutInterval = 15
        
        let body: [String: String] = [
            "token": token,
            "new_password": newPassword
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        } catch {
            completion(.failure(.serverError))
            return
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if error != nil {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.serverError))
                return
            }
            
            switch httpResponse.statusCode {
            case 200:
                completion(.success(()))
            case 401, 403:
                completion(.failure(.tokenInvalid))
            case 410:
                completion(.failure(.tokenExpired))
            case 422:
                completion(.failure(.weakPassword))
            default:
                completion(.failure(.serverError))
            }
        }
        task.resume()
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private var deepLinkHandler: DeepLinkHandler?
    private var coordinator: NavigationCoordinator?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let rootVC = UIViewController() // Replace with your actual root view controller
        rootVC.view.backgroundColor = .systemBackground
        let navController = UINavigationController(rootViewController: rootVC)
        window.rootViewController = navController
        window.makeKeyAndVisible()
        self.window = window
        
        let coordinator = NavigationCoordinator(window: window)
        self.coordinator = coordinator
        self.deepLinkHandler = DeepLinkHandler(coordinator: coordinator)
        
        // Handle universal links from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleIncomingURL(url)
        }
    }
    
    // Handle universal links when app is already running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    // Handle custom URL scheme (fallback)
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        _ = deepLinkHandler?.handleUniversalLink(url)
    }
}

// MARK: - AppDelegate Integration (for iOS 12 and below or non-scene apps)

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    private var deepLinkHandler: DeepLinkHandler?
    private var coordinator: NavigationCoordinator?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        // Only set up window if not using scenes
        if #available(iOS 13.0, *) {
            // Scene delegate handles window setup
        } else {
            let window = UIWindow(frame: UIScreen.main.bounds)
            let rootVC = UIViewController()
            rootVC.view.backgroundColor = .systemBackground
            let navController = UINavigationController(rootViewController: rootVC)
            window.rootViewController = navController
            window.makeKeyAndVisible()
            self.window = window
            
            let coordinator = NavigationCoordinator(window: window)
            self.coordinator = coordinator
            self.deepLinkHandler = DeepLinkHandler(coordinator: coordinator)
        }
        
        return true
    }
    
    // Handle universal links (iOS 12 and below)
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return deepLinkHandler?.handleUniversalLink(url) ?? false
    }
    
    // MARK: UISceneSession Lifecycle
    
    @available(iOS 13.0, *)
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        return UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
    }
